function doGet(e) {
  // 1. Obtenemos el ID desde la URL: ?id=VALOR
  var fileId = e.parameter.id;

  if (!fileId) {
    return ContentService.createTextOutput("Error: Falta el parámetro ID en la URL.")
           .setMimeType(ContentService.MimeType.TEXT);
  }

  try {
    // 2. Leemos el archivo de Drive
    var file = DriveApp.getFileById(fileId);
    var content = file.getBlob().getDataAsString();

    // 3. Lo escupimos como TEXTO PLANO para que el sitio destino lo maneje
    // Esto evita que Google rompa el CSS o las fuentes
    return ContentService.createTextOutput(content)
           .setMimeType(ContentService.MimeType.TEXT);

  } catch (err) {
    return ContentService.createTextOutput("Error: No se encontró el archivo o no tienes permisos.")
           .setMimeType(ContentService.MimeType.TEXT);
  }
}
